/**
 * Function: Test batch execution reduces recomputation count
 *
 * @param initialA Initial value for variable a
 * @param initialB Initial value for variable b
 * @param nonBatchA Value to set a without batching
 * @param nonBatchB Value to set b without batching
 * @param batchA Value to set a within batch
 * @param batchB Value to set b within batch
 * @return std::tuple<int, int, int> {final sum, count after non-batch updates, count after batch updates}
 */
std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    // 1. Create reactive variables
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);

    // 2. Create variable to track recomputation count
    int recomputeCount = 0;

    // 3. Create calculation that depends on both a and b
    auto sum = reaction::calc([&] {
        recomputeCount++;
        return a() + b();
    });

    // Force initial evaluation
    int initialSum = sum();

    // Reset counter after initial evaluation
    recomputeCount = 0;

    // 4. Perform non-batch updates
    a = nonBatchA;
    b = nonBatchB;

    // Force evaluation after non-batch updates
    int nonBatchSum = sum();

    // 5. Record recompute count after non-batch updates
    int countAfterNonBatch = recomputeCount;

    // Reset counter for batch test
    recomputeCount = 0;

    // 6. Create batch context
    {
        reaction::batch batch_ctx;

        // 7. Execute batch updates
        a = batchA;
        b = batchB;

        // Batch context automatically executes when it goes out of scope
    }

    // Force evaluation after batch updates
    int batchSum = sum();

    // 8. Record recompute count after batch updates
    int countAfterBatch = recomputeCount;

    // 9. Return final sum and counts
    return std::make_tuple(batchSum, countAfterNonBatch, countAfterBatch);
}

}  // namespace test_reaction
```

This implementation:

1. Creates reactive variables `a` and `b` using `reaction::var()`
2. Tracks recomputation count with a simple integer counter
3. Creates a calculation that sums `a` and `b` using `reaction::calc()`
4. Performs non-batch updates by directly assigning to the reactive variables
5. Records the recomputation count after non-batch updates
6. Creates a batch context using `reaction::batch`
7. Executes batch updates within the batch context
8. Records the recomputation count after batch updates
9. Returns the final sum and both counts as a tuple

The key insight is that batch execution should reduce the number of recomputations - without batching, each variable update triggers a separate recomputation, but with batching, multiple updates are batched together and only trigger one recomputation.

