/**
 * Function: Test naming reactive nodes and retrieving names
 *
 * @param valueA Initial value for varA
 * @param valueB Initial value for varB
 * @return std::string Combined string of retrieved names
 */
std::string test_named_reactions(int valueA, int valueB) {
    // 1. Create reactive variables with names
    auto varA = reaction::var(valueA).name("varA");
    auto varB = reaction::var(valueB).name("varB");

    // 2. Create calculations with names
    auto calcSum = reaction::calc([varA, varB]() {
        return varA.get() + varB.get();
    }).name("calcSum");

    auto calcProduct = reaction::calc([varA, varB]() {
        return varA.get() * varB.get();
    }).name("calcProduct");

    // 3. Create action with name
    std::string actionResult;
    auto action = reaction::action([&actionResult, varA, varB]() {
        actionResult = "Action executed with varA=" + std::to_string(varA.get()) + 
                      ", varB=" + std::to_string(varB.get());
    }).name("testAction");

    // Execute the action to demonstrate it works
    action();

    // 4. Retrieve names
    std::string varAName = varA.getName();
    std::string varBName = varB.getName();
    std::string calcSumName = calcSum.getName();
    std::string calcProductName = calcProduct.getName();
    std::string actionName = action.getName();

    // 5. Return combined names string
    std::ostringstream result;
    result << "Variables: " << varAName << ", " << varBName 
           << " | Calculations: " << calcSumName << ", " << calcProductName
           << " | Action: " << actionName
           << " | Action Result: " << actionResult;

    return result.str();
}

}  // namespace test_reaction
