    reaction::Var<double> sensor(initialValue);

    // 2. Create variables to track recomputation count and last processed value
    int recomputeCount = 0;
    double lastProcessedValue = initialValue;

    // 3. Create filter-triggered calculation
    auto statusCalc = reaction::Computed([&]() -> std::string {
        recomputeCount++;
        double current = sensor.get();
        lastProcessedValue = current;

        if (current >= levelThreshold) {
            return "HIGH";
        } else {
            return "NORMAL";
        }
    });

    // 4. Apply filter
    auto filteredSensor = reaction::Filter(sensor, [&](double newValue) {
        return std::abs(newValue - lastProcessedValue) >= diffThreshold;
    });

    // Create a reaction that updates when filtered sensor changes
    reaction::Reaction reaction(
        filteredSensor,
        [&](double value) {
            // Force recomputation by accessing the status
            statusCalc.get();
        }
    );

    // 5. Update sensor with first value
    sensor.set(firstUpdate);

    // 6. Record recompute count after first update
    int countAfterFirst = recomputeCount;

    // 7. Update sensor with second value
    sensor.set(secondUpdate);

    // 8. Record recompute count after second update
    int countAfterSecond = recomputeCount;

    // 9. Get final status
    std::string finalStatus = statusCalc.get();

    // 10. Return final status and counts
    return {finalStatus, countAfterFirst, countAfterSecond};
}

}  // namespace test_reaction

