Here's the complete implementation:

```cpp
#pragma once

#include <reaction/reaction.h>
#include <string>
#include <memory>

namespace test_reaction {

class NamedObserverNode : public reaction::ObserverNode {
public:
    explicit NamedObserverNode(std::string name) : name_(std::move(name)) {}

    const std::string& name() const { return name_; }

private:
    std::string name_;
};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

inline ObserverCollectionSummary test_observer_collection() {
    // 1. Create NamedObserverNode instances
    auto nodeA = std::make_shared<NamedObserverNode>("NodeA");
    auto nodeB = std::make_shared<NamedObserverNode>("NodeB");
    auto nodeC = std::make_shared<NamedObserverNode>("NodeC");
    auto nodeD = std::make_shared<NamedObserverNode>("NodeD");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes (nodes are automatically registered when observers are added)

    // 4. Set up direct observer relationship: nodeB observes nodeA
    nodeA->addOneObserver(nodeB);

    // 5. Set up transitive observer relationship: nodeC observes nodeB, making nodeC transitive observer of nodeA
    nodeB->addOneObserver(nodeC);

    // Also add a direct observer to test both cases
    nodeA->addOneObserver(nodeD);

    // 6. Create NodeSet to store collected observers
    reaction::ObserverGraph::NodeSet collectedObservers;

    // 7. Collect observers for nodeA
    graph.collectObservers(nodeA, collectedObservers);

    // 8. Check if direct observer is in collected set
    bool hasDirectObserver = false;
    bool hasTransitiveObserver = false;

    for (const auto& observer : collectedObservers) {
        if (auto namedObserver = std::dynamic_pointer_cast<NamedObserverNode>(observer)) {
            if (namedObserver->name() == "NodeB") {
                hasDirectObserver = true;
            } else if (namedObserver->name() == "NodeC") {
                hasTransitiveObserver = true;
            }
        }
    }

    // 10. Return collection summary
    return ObserverCollectionSummary{
        collectedObservers.size(),
        hasDirectObserver,
        hasTransitiveObserver
    };
}

}  // namespace test_reaction
```

