    auto largeResource = std::make_shared<reaction::memory::SBOResource<LargePayload>>(
        makeLargePayload()
    );

    // 4. Update small resource value and check if change was reported
    bool updateReportedChange = smallResource->updateValue(SmallPayload{updatedSmall});

    // 5. Get storage information for small resource
    bool smallUsingSBO = smallResource->isUsingSBO();
    std::size_t smallStackUsage = sizeof(*smallResource); // Approximate stack usage

    // 6. Get storage information for large resource
    bool largeInitialized = (largeResource->getValue().data[0] == largeSeed);
    bool largeUsingSBO = largeResource->isUsingSBO();

    // 7. Return SBO storage status
    return SboStorageStatus{
        updateReportedChange,
        smallUsingSBO,
        smallStackUsage,
        largeInitialized,
        largeUsingSBO
    };
