    // 1. Create NodeMetricsCache instance
    auto cache = std::make_shared<reaction::NodeMetricsCache>();

    // 2. Create ObserverNode instance
    auto node = std::make_shared<reaction::ObserverNode>();

    // 3. Get cache statistics before caching
    auto stats_before = cache->getStatistics();
    std::size_t entriesBefore = stats_before.entryCount;

    // 4. Query metrics before caching
    auto metrics_before = cache->getNodeMetrics(node);
    bool metricsCachedExists = (metrics_before != nullptr);

    // 5. Cache node metrics
    cache->cacheNodeMetrics(node);

    // 6. Query metrics after caching
    auto metrics_after_cache = cache->getNodeMetrics(node);
    metricsCachedExists = (metrics_after_cache != nullptr);

    // 7. Get cache statistics after caching
    auto stats_after_cache = cache->getStatistics();
    std::size_t entriesAfterCache = stats_after_cache.entryCount;

    // 8. Invalidate all entries
    cache->invalidateAll();

    // 9. Query metrics after invalidation
    auto metrics_after_invalidate = cache->getNodeMetrics(node);
    bool metricsClearedAfterInvalidate = (metrics_after_invalidate == nullptr);

    // 10. Get cache statistics after invalidation
    auto stats_after_invalidate = cache->getStatistics();
    std::size_t entriesAfterInvalidate = stats_after_invalidate.entryCount;

